<template>

    <div class="container">

        <h1>tabla vendedores</h1>
        <table>

            <thead>

                <tr>

                    <th>Codigo</th>
                    <th>Nombre</th>
                    <th>Empresa</th>
                    <th>Productos</th>
                    <th>Telefono</th>
                </tr>
            </thead>

            <tbody>

                <tr v-for="vendedor in vendedores" :key="vendedor.codigo">

                    <td>{{vendedor.codigo}}</td>
                    <td>{{vendedor.nombre}}</td>
                    <td>{{vendedor.empresa}}</td>
                    <td>{{vendedor.productos}}</td>
                    <td>{{vendedor.telefono}}</td>
                </tr>
                

            </tbody>
        </table>
    </div>
</template>
<script>

import axios from "axios"

export default{

    data(){

        return{

            vendedores:[],
        };
    },

    methods:{

        obtenerVendedores(){


            axios.get("http://localhost:8080/api/vendedores/listar")
            .then((response)=>{

                this.vendedores=response.data;

            })
            .catch((error)=>{

                console.error("error al obtener los vendedores",error);

            });
        },
    },

    mounted(){
        this.obtenerVendedores();
    },

};
</script>