<template>


    <div class="container">

        <h1>Formulario de Productos</h1>

        <form id="formulario-productos" @submit.prevent="guardar">


            <div class="form-group">


                <label for="codigo">codigo</label>
                <input type="text" id="codigo" name="codigo" required v-model="codigo"/>
            </div>
            <div class="form-group">


                <label for="nombre">nombre</label>
                <input type="text" id="nombre" name="nombre" required v-model="nombre"/>
            </div>
            <div class="form-group">


                <label for="empresa">empresa</label>
                <input type="text" id="empresa" name="empresa" required v-model="empresa"/>
            </div>
            <div class="form-group">


                <label for="gramaje">gramaje</label>
                <input type="text" id="gramaje" name="gramaje" required v-model="gramaje"/>
            </div>
            <div class="form-group">


                <label for="precio">precio</label>
                <input type="text" id="precio" name="precio" required v-model="precio"/>
            </div>

            <button type="submit">Guardar</button><br>
            <button type="button" @click="eliminar">Eliminar</button><br>
            <button type="button" @click="actualizar">Actualizar</button><br>
            <button type="button" @click="consultar">Consultar</button><br>


        </form>
    </div>
</template>

<script>

import axios from "axios";

export default{

    data(){

        return{

            codigo:"",
            nombre:"",
            empresa:"",
            gramaje:"",
            precio:"",

        }; 

    },
    methods:{

        guardar(){

            axios.post("https://modulo4-production-5b1d.up.railway.app/api/productos",{ 
             

                codigo: this.codigo,
                nombre: this.nombre,
                empresa: this.empresa,
                gramaje: this.gramaje,
                precio: this.precio,
        
             })

             .then((Response)=>{

                console.log("el producto fue registrado con exito", Response.data);
                alert("el producto se registro correctamente");
                this.codigo="";
                this.nombre="";
                this.empresa="";
                this.gramaje="";
                this.precio="";
                this.$emit("actualizar-tabla");

             })
             .catch((error)=>{

                console.error("error al registrar el producto",error);
                alert("registro fallo")



                
             });


        },

        consultar(){

            axios.get("https://modulo4-production-5b1d.up.railway.app/api/productos/"+this.codigo)
            .then((response)=>{

                this.nombre= response.data.nombre;
                this.empresa=response.data.empresa;
                this.gramaje=response.data.gramaje;
                this.precio=response.data.precio;
            })
            .catch((error)=>{

                console.error("error al consultar el producto", error);
            });
        },
        actualizar(){

            axios.put("https://modulo4-production-5b1d.up.railway.app/api/productos/actualizar/"+this.codigo,{

                codigo:this.codigo,
                nombre:this.nombre,
                empresa:this.empresa,
                gramaje:this.gramaje,
                precio:this.precio,
            })
            .then((response)=>{
                console.log("producto registrado con exito",response.data);
                alert("producto actualizado con exito");
                this.$emit("actualizar-tabla");
            })
            .catch((error)=>{


                console.log("error al actualizar el producto",error);

                
            });

        },

        eliminar(){

            axios.delete("https://modulo4-production-5b1d.up.railway.app/api/productos/"+this.codigo)
            .then(()=>{

                alert("producto aliminado con exito");
                this.codigo="";
                this.nombre="";
                this.empresa="";
                this.gramaje="";
                this.precio="";
                this.$emit("actualizar-tabla");
            })
            .catch((error)=>{


                console.error("error al eliminar el producto",error);
            })





        }



    },
    
};



</script>