<template>

    <div class="container">

        <h1>tabla productos</h1>


        <table>

            <thead>

                <tr>

                    <th>Codigo</th>
                    <th>Nombre</th>
                    <th>Empresa</th>
                    <th>Gramaje</th>
                    <th>Precio</th>

                </tr>



            </thead>
            <tbody>

                <tr v-for="producto in productos" :key="producto.codigo">

                    <td>{{producto.codigo}}</td>
                    <td>{{producto.nombre}}</td>
                    <td>{{producto.empresa}}</td>
                    <td>{{producto.gramaje}}</td>
                    <td>{{producto.precio}}</td>

                </tr>
                
            </tbody>





        </table>



    </div>
</template>

<script>

import axios from "axios";

export default {

   data(){

       return{

            productos:[],
        


           };
   },

   methods:{


    obtenerProductos(){

        axios.get("https://modulo4-production-5b1d.up.railway.app/api/productos/listar")
        .then((response)=>{



            this.productos=response.data;
        })
        .catch((error)=>{


            console.error("error al obtener los productos",error);
        });



    },

   },

   mounted(){


    this.obtenerProductos();
   }


}




</script>