<template>

    <div class="container">

        <h1>Formulario de Vendedores</h1>

        <form id="formulario-vendedores" @submit.prevent="guardar">


            <div class="form-group">


                <label for="codigo">Codigo</label>
                <input type="text" id="codigo" name="codigo" required v-model="codigo"/>
            </div>
            
            <div class="form-group">


                <label for="nombre">Nombre</label>
                <input type="text" id="nombre" name="nombre" required v-model="nombre"/>
            </div>
            
            <div class="form-group">


                <label for="empresa">Empresa</label>
                <input type="text" id="empresa" name="empresa" required v-model="empresa"/>
            </div>
            
            <div class="form-group">


                <label for="productos">Productos</label>
                <input type="text" id="productos" name="productos" required v-model="productos"/>
            </div>
            
            <div class="form-group">


                <label for="telefono">Telefono</label>
                <input type="text" id="telefono" name="telefono" required v-model="telefono"/>
            </div>

            <button type="submit">Guardar</button><br>
            <button type="button" @click="eliminar">Eliminar</button><br>
            <button type="button" @click="actualizar">Actualizar</button><br>
            <button type="button" @click="consultar">Consultar</button><br>

        </form>
    </div>
</template>

<script>

    import axios from "axios";

    export default{

        data(){

            return{

            codigo:"",
            nombre:"",
            empresa:"",
            productos:"",
            telefono:"",

                
            };

        },

        methods:{

              guardar(){
                axios.post("http://localhost:8080/api/vendedores",{



                    codigo: this.codigo,
                    nombre: this.nombre,
                    empresa: this.empresa,
                    productos: this.productos,
                    telefono: this.telefono,
                })

                .then((response)=>{
                    console.log("vendedor registrado con exito", response.data);
                    alert("el vendedor se registro correctamente");
                    this.codigo="";
                    this.nombre="";
                    this.empresa="";
                    this.productos="";
                    this.telefono="";
                    this.$emit("actualizar-tabla");
                })
                .catch((error)=>{

                    console.error("error al registrar vendedor", error);
                    alert("registro fallo")
                });
              },


              consultar(){

                axios.get("http://localhost:8080/api/vendedores/"+this.codigo)
                .then((response)=>{


                    this.nombre= response.data.nombre;
                    this.empresa= response.data.empresa;
                    this.productos= response.data.productos;
                    this.telefono= response.data.telefono;
                })
                .catch((error)=>{

                    console.error("error al consultar el vendedor", error);

                });




              },
              actualizar(){

                axios.put("http://localhost:8080/api/vendedores/actualizar/"+this.codigo,{


                    codigo:this.codigo,
                    nombre:this.nombre,
                    empresa:this.empresa,
                    productos:this.productos,
                    telefono:this.telefono,

                })
                .then((response)=>{

                    console.log("vendedor actualizado con exito", response.data);
                    alert("vendedor actualizado con exito");
                    this.$emit("actualizar-tabla");

                })
                .catch((error)=>{
                    console.error("error al actualizaar el vendedor",error);

                });
              },

              eliminar(){

                axios.delete("http://localhost:8080/api/vendedores/"+this.codigo)

                .then(()=>{

                    alert("vendedor eliminado con exito");
                    this.codigo="";
                    this.nombre="";
                    this.empresa="";
                    this.productos="";
                    this.telefono="";
                    this.$emit("actualizar-tabla");
                })
                .catch((error)=>{

                    console.error("error al eliminar el vendedor", error);
                })
              }
        },
    };
</script>